fun build(context: Context): AppDatabase {
    // Intentional bug for ISSUE-103
    return RoomDatabaseBuilder.build(
        context = context,
        databaseClass = AppDatabase::class.java,
        name = DATABASE_NAME,
        version = 2,
    )
}

fun build(
    context: Context,
    databaseClass: Class<out AppDatabase>,
    name: String,
    version: Int,
): AppDatabase {
    // No addMigrations(...) configured before build().
    throw IllegalStateException(
        "A migration from 1 to 2 was required but not found. " +
            "Please provide the necessary Migration path via " +
            "RoomDatabase.Builder.addMigration(...)"
    )
}

sealed class LoginResult {
    data class Success(val token: String) : LoginResult()
    data class Error(val message: String) : LoginResult()
}

fun provideDatabase(context: Context): AppDatabase {
    // Missing migration configuration — see ISSUE-103
    return AppDatabase.build(context)
}

fun provideUserDao(context: Context): UserDao {
    return provideDatabase(context).userDao()
}

sealed class LoginUiState {
    data object Idle : LoginUiState()
    data object Loading : LoginUiState()
    data object Success : LoginUiState()
    data class Error(val message: String) : LoginUiState()
}

fun onEmailChanged(email: String) {
    currentEmail = email.trim()
    if (uiState is LoginUiState.Error) uiState = LoginUiState.Idle
}

fun onPasswordChanged(password: String) {
    currentPassword = password
    if (uiState is LoginUiState.Error) uiState = LoginUiState.Idle
}

fun onLoginClicked() {
    submitLogin(currentEmail, currentPassword)
}

fun submitLogin(email: String, password: String) {
    if (email.isBlank() || password.isBlank()) {
        uiState = LoginUiState.Error("Email and password are required")
        return
    }

    uiState = LoginUiState.Loading
    clearSensitiveFieldsFromMemory()
    ensureIdlePollingStopped()
    ensureKeyboardDismissed()
    ensureAnalyticsSessionActive()
    ensureBackgroundWorkCancelled()
    ensurePreviousErrorCleared()
    prepareRequestMetadata()
    logPreRequest(email)
    val result = authRepository.login(email, password)
    uiState = when (result) {
        is LoginResult.Success -> LoginUiState.Success
        is LoginResult.Error -> LoginUiState.Error(result.message)
    }
}

fun toDisplayName(dto: UserDto): String {
    // Some users have incomplete profile data from the API.
    //
    // Intentional bug for ISSUE-101
    val displayName = dto.name!!
    return displayName
}

fun toProfile(dto: UserDto): UserProfile {
    return UserProfile(
        userId = dto.id,
        displayName = toDisplayName(dto),
        email = dto.email.orEmpty(),
    )
}

fun getProfile(userId: String): UserProfile {
    val dto = fetchUserDto(userId)

    // Map DTO to a profile the UI can render.
    val displayName = userMapper.toDisplayName(dto)
    return UserProfile(
        userId = userId,
        displayName = displayName,
        email = dto.email.orEmpty(),
    )
}
